SELECT average_rating 
FROM app_trends 
WHERE app_id = 1;

SELECT COUNT(DISTINCT user_id)
FROM notifications
WHERE app_id = (SELECT app_id FROM apps WHERE app_name = 'Acorns');

SELECT category, COUNT(*) as Number_of_Apps
FROM apps
GROUP BY category;

SELECT u.*
FROM users u
WHERE u.user_id IN (
    SELECT r.user_id
    FROM reviews r
    WHERE r.user_id NOT IN (
        SELECT ra.user_id
        FROM ratings ra
    )
);

SELECT COUNT(DISTINCT user_id) 
FROM reviews 
WHERE app_id = 1;

SELECT AVG(rating_value) AS typical_feedback_score
FROM ratings
WHERE app_id = (SELECT app_id FROM apps WHERE app_name = 'Stash Invest');
